module BrentKungAdder (
    input [3:0] A,
    input [3:0] B,
    input Cin,
    output [3:0] S,
    output Cout
);
    wire [3:0] P; // Propagate
    wire [3:0] G; // Generate
    wire [4:0] obf_C; // Carry

    assign P = A ^ B; // Propagate
    assign G = A & B; // Generate

    // Carry calculation
    assign obf_C[0] = Cin;
    assign obf_C[1] = G[0] | (P[0] & obf_C[0]);
    assign obf_C[2] = G[1] | (P[1] & obf_C[1]);
    assign obf_C[3] = G[2] | (P[2] & obf_C[2]);
    assign obf_C[4] = G[3] | (P[3] & obf_C[3]);

    // Sum calculation
    assign S = P ^ {obf_C[3:0]};

    assign Cout = obf_C[4];
endmodule
